```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract DeadlineAuction is ReentrancyGuard {
    address public seller;
    uint256 public deadline;
    address public highestBidder;
    uint256 public highestBid;
    mapping(address => uint256) public pendingRefunds;

    event Bid(address indexed sender, uint256 value);
    event Refund(address indexed bidder, uint256 amount);
    event AuctionFinalized(address indexed seller, uint256 totalBids);

    constructor(address _seller, uint256 _deadline) {
        require(_deadline > block.timestamp, "Invalid deadline");
        seller = _seller;
        deadline = _deadline;
    }

    modifier onlyBeforeDeadline() {
        require(block.timestamp <= deadline, "Auction has ended");
        _;
    }

    function bid() external payable onlyBeforeDeadline {
        require(msg.value > highestBid, "Bid must be higher than the current highest bid.");
        if (highestBid != 0) {
            pendingRefunds[highestBidder] += highestBid;
            emit Refund(highestBidder, highestBid);
        }
        highestBidder = msg.sender;
        highestBid = msg.value;
        emit Bid(msg.sender, msg.value);
    }

    function withdrawRefund() external nonReentrant {
        uint256 refundAmount = pendingRefunds[msg.sender];
        require(refundAmount > 0, "No refund available");
        delete pendingRefunds[msg.sender];
        (bool success, ) = payable(msg.sender).call{value: refundAmount}("");
        require(success, "Failed to send Ether");
        emit Refund(msg.sender, refundAmount);
    }

    function finalizeAuction() external onlySeller {
        require(block.timestamp >= deadline, "Auction has not ended");
        uint256 totalBids = highestBid;
        (bool success, ) = payable(seller).call{value: totalBids}("");
        require(success, "Transfer failed");
        emit AuctionFinalized(seller, totalBids);
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Only seller can finalize auction");
        _;
    }

    function getCurrentHighestBidder() external view returns (address) {
        return highestBidder;
    }

    function getHighestBid() external view returns (uint256) {
        return highestBid;
    }

    function getDeadline() external view returns (uint256) {
        return deadline;
    }

    function getPendingRefund(address user) external view returns (uint256) {
        return pendingRefunds[user];
    }
}
