    uint256 public deadline;
    address public highestBidder;
    uint256 public highestBid;
    mapping(address => uint256) public pendingRefunds;

    event Bid(address indexed sender, uint256 value);
    event Refund(address indexed bidder, uint256 amount);
    event AuctionFinalized(address indexed seller, uint256 amount);

    modifier onlyBeforeDeadline() {
        require(block.timestamp < deadline, "Auction has ended.");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Not the seller.");
        _;
    }

    constructor(address _seller, uint256 _deadline) {
        seller = _seller;
        deadline = _deadline;
    }

    function bid() external payable onlyBeforeDeadline {
        require(msg.value > highestBid, "New bid must be higher than the current highest bid.");

        if (highestBid != 0) {
            pendingRefunds[highestBidder] += highestBid;
        }

        highestBidder = msg.sender;
        highestBid = msg.value;

        emit Bid(msg.sender, msg.value);
    }

    function withdrawRefund() external {
        uint256 refundAmount = pendingRefunds[msg.sender];
        pendingRefunds[msg.sender] = 0;

        if (refundAmount > 0) {
            (bool sent, ) = msg.sender.call{value: refundAmount}("");
            require(sent, "Failed to send Ether");

            emit Refund(msg.sender, refundAmount);
        }
    }

    function finalizeAuction() external onlySeller onlyBeforeDeadline {
        require(block.timestamp >= deadline, "Auction has not yet ended.");

        payable(seller).transfer(highestBid);

        emit AuctionFinalized(seller, highestBid);
    }

    function getCurrentHighestBidder() external view returns (address) {
        return highestBidder;
    }

    function getHighestBid() external view returns (uint256) {
        return highestBid;
    }

    function getDeadline() external view returns (uint256) {
        return deadline;
    }

    function getPendingRefund(address user) external view returns (uint256) {
        return pendingRefunds[user];
